import React from "react";
import "./Intro.css";
import { Button } from "./button";

export const Intro = () => {
  return (
    <div id="intro-container">
      <button size="small" text="small" />
      <button size="medium" text="medium" />
      <button size="large" text="large" />
      <button>
        <span>Normal</span>
      </button>
    </div>
  );
};
